import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Jovem } from '../types';

const JovensList: React.FC = () => {
  const { user } = useAuth();
  const [jovens, setJovens] = useState<Jovem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchJovens = async () => {
      try {
        setLoading(true);
        const response = await fetch('/api/jovens', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });

        if (!response.ok) {
          throw new Error('Erro ao carregar jovens');
        }

        const data = await response.json();
        setJovens(data);
        setLoading(false);
      } catch (error) {
        console.error('Erro:', error);
        setError('Erro ao carregar dados. Por favor, tente novamente.');
        setLoading(false);
      }
    };

    fetchJovens();
  }, []);

  const getBasePath = () => {
    if (user?.papel === 'instituicao_ensino') {
      return '/instituicao-ensino';
    } else if (user?.papel === 'chefe_empresa') {
      return '/chefe-empresa';
    } else if (user?.papel === 'instituicao_contratante') {
      return '/instituicao-contratante';
    }
    return '';
  };

  const handleNovoJovem = () => {
    navigate(`${getBasePath()}/jovens/novo`);
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-2xl font-bold text-cursor-text-primary">Jovens</h1>
          <div className="text-sm text-cursor-text-secondary mt-1">
            Gerenciamento de jovens {user?.papel === 'instituicao_ensino' ? 'da instituição' : 'da empresa'}
          </div>
        </div>
        <button
          onClick={handleNovoJovem}
          className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-cursor-primary hover:bg-cursor-primary-dark"
        >
          <svg className="-ml-1 mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" />
          </svg>
          Adicionar Jovem
        </button>
      </div>

      <div className="bg-white rounded-lg shadow mb-8">
        <div className="p-4">
          {loading ? (
            <div className="text-center py-4">Carregando...</div>
          ) : error ? (
            <div className="text-center py-4 text-red-500">{error}</div>
          ) : jovens.length === 0 ? (
            <div className="text-center py-8">
              <svg className="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
              </svg>
              <h3 className="mt-2 text-sm font-medium text-cursor-text-primary">Nenhum jovem cadastrado</h3>
              <p className="mt-1 text-sm text-cursor-text-secondary">Comece adicionando seu primeiro jovem ao sistema.</p>
              <div className="mt-6">
                <button
                  onClick={handleNovoJovem}
                  className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-cursor-primary hover:bg-cursor-primary-dark focus:outline-none"
                >
                  <svg className="-ml-1 mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" />
                  </svg>
                  Adicionar Jovem
                </button>
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nome</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Idade</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Formação</th>
                    {user?.papel === 'chefe_empresa' && (
                      <>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Cargo</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                      </>
                    )}
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {jovens.map(jovem => (
                    <tr key={jovem.id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-cursor-text-primary">{jovem.nome}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{jovem.email}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{jovem.idade}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{jovem.formacao || '-'}</td>
                      {user?.papel === 'chefe_empresa' && (
                        <>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">
                            {jovem.empresas && jovem.empresas.length > 0 ? jovem.empresas[0].cargo : '-'}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">
                            {jovem.empresas && jovem.empresas.length > 0 ? (
                              <span className={`px-2 py-1 text-xs rounded-full ${
                                jovem.empresas[0].status === 'Contratado' ? 'bg-green-100 text-green-800' : 
                                jovem.empresas[0].status === 'Estagiário' ? 'bg-blue-100 text-blue-800' : 
                                'bg-gray-100 text-gray-800'
                              }`}>
                                {jovem.empresas[0].status}
                              </span>
                            ) : '-'}
                          </td>
                        </>
                      )}
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <Link to={`${getBasePath()}/jovens/${jovem.id}`} className="text-cursor-primary hover:underline">
                          Detalhes
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default JovensList;
